@namespace sv_eaddef93421840ad96f12f92eec1e88d.Components.Pages.Settings

<nav class="settings-sidebar">
    <h5 class="px-3 py-2 text-muted">Settings</h5>
    <ul class="nav flex-column">
        @foreach (var section in Sections)
        {
            <li class="nav-item">
                <button class="nav-link @(section == ActiveSection ? "active" : "")"
                        @onclick="() => OnSectionChanged.InvokeAsync(section)">
                    <span class="me-2">@GetIcon(section)</span>@section
                </button>
            </li>
        }
    </ul>
</nav>

@code {
    private static readonly string[] Sections = { "Profile", "Notifications", "Security", "Appearance" };

    [Parameter] public string ActiveSection { get; set; } = "Profile";
    [Parameter] public EventCallback<string> OnSectionChanged { get; set; }

    private static string GetIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };
}

@namespace sv_eaddef93421840ad96f12f92eec1e88d.Components.Pages.Settings
@using sv_eaddef93421840ad96f12f92eec1e88d.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Profile</h3>
    <hr />

    @if (_loading)
    {
        <p class="text-muted">Loading profile...</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert @(_messageIsError ? "alert-danger" : "alert-success") alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-8">
                <div class="mb-3">
                    <label class="form-label">Display Name</label>
                    <input type="text" class="form-control" @bind="_displayName" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Email</label>
                    <input type="email" class="form-control" @bind="_email" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Bio</label>
                    <textarea class="form-control" rows="4" @bind="_bio"></textarea>
                </div>
            </div>
            <div class="col-md-4 text-center">
                <div class="avatar-preview mb-2">
                    <img src="@_avatarUrl" alt="Avatar" class="rounded-circle" style="width:100px;height:100px;object-fit:cover;" />
                </div>
                <small class="text-muted d-block text-truncate" style="max-width:200px;" title="@_avatarUrl">@_avatarUrl</small>
            </div>
        </div>

        <div class="d-flex gap-2 mt-3">
            <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                @(_saving ? "Saving..." : "Save Changes")
            </button>
            <button class="btn btn-outline-secondary" @onclick="Discard">
                Discard Changes
            </button>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;
    private bool _messageIsError;

    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    private UserProfile? _savedProfile;

    protected override async Task OnInitializedAsync()
    {
        var profile = await SettingsService.GetProfileAsync();
        _savedProfile = profile;
        ApplyProfile(profile);
        _loading = false;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        try
        {
            var updated = new UserProfile(_displayName, _email, _avatarUrl, _bio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            _message = "Profile saved successfully!";
            _messageIsError = false;
        }
        catch (Exception ex)
        {
            _message = $"Failed to save: {ex.Message}";
            _messageIsError = true;
        }
        finally
        {
            _saving = false;
        }
    }

    private void Discard()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
            _message = null;
        }
    }
}

@namespace sv_eaddef93421840ad96f12f92eec1e88d.Components.Pages.Settings
@using sv_eaddef93421840ad96f12f92eec1e88d.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Notifications</h3>
    <hr />

    @if (_loading)
    {
        <p class="text-muted">Loading notification preferences...</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="mb-4">
            <h5>Notification Channels</h5>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>
            <div class="form-check form-switch mb-2">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>
        </div>

        <div class="mb-4">
            <h5>Muted Channels</h5>
            <p class="text-muted small">Uncheck a channel to unmute it.</p>
            @foreach (var channel in _channels)
            {
                <div class="form-check mb-1">
                    <input class="form-check-input" type="checkbox" id="@($"ch-{channel.Name}")"
                           checked="@channel.Muted"
                           @onchange="e => ToggleChannel(channel.Name, (bool)(e.Value ?? false))" />
                    <label class="form-check-label" for="@($"ch-{channel.Name}")">@channel.Name</label>
                </div>
            }
        </div>

        <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
            @(_saving ? "Saving..." : "Save Preferences")
        </button>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<ChannelItem> _channels = new();

    private record ChannelItem(string Name, bool Muted);

    protected override async Task OnInitializedAsync()
    {
        var prefs = await SettingsService.GetNotificationPrefsAsync();
        _emailNotifications = prefs.EmailNotifications;
        _pushNotifications = prefs.PushNotifications;
        _weeklyDigest = prefs.WeeklyDigest;
        _channels = prefs.MutedChannels.Select(c => new ChannelItem(c, true)).ToList();
        _loading = false;
    }

    private void ToggleChannel(string name, bool muted)
    {
        var idx = _channels.FindIndex(c => c.Name == name);
        if (idx >= 0)
            _channels[idx] = _channels[idx] with { Muted = muted };
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var mutedList = _channels.Where(c => c.Muted).Select(c => c.Name).ToList();
        var prefs = new NotificationPrefs(_emailNotifications, _pushNotifications, _weeklyDigest, mutedList);
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        _message = "Notification preferences saved!";
        _saving = false;
    }
}

