.settings-layout {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding-top: 1rem;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    text-align: left;
    width: 100%;
    border: none;
    background: none;
    font-size: 0.95rem;
    transition: background-color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    max-width: 900px;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
