@namespace sv_eaddef93421840ad96f12f92eec1e88d.Components.Pages.Settings
@using sv_eaddef93421840ad96f12f92eec1e88d.Services
@inject ISettingsService SettingsService

<div class="settings-section">
    <h3>Appearance</h3>
    <hr />

    @if (_loading)
    {
        <p class="text-muted">Loading appearance settings...</p>
    }
    else
    {
        @if (!string.IsNullOrEmpty(_message))
        {
            <div class="alert alert-success alert-dismissible fade show" role="alert">
                @_message
                <button type="button" class="btn-close" @onclick="() => _message = null"></button>
            </div>
        }

        <div class="row">
            <div class="col-md-6">
                <!-- Theme -->
                <div class="mb-4">
                    <h5>Theme</h5>
                    @foreach (var theme in new[] { "Light", "Dark", "System" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="theme"
                                   id="@($"theme-{theme}")" value="@theme"
                                   checked="@(_theme == theme)"
                                   @onchange="() => _theme = theme" />
                            <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                        </div>
                    }
                </div>

                <!-- Font Size -->
                <div class="mb-4">
                    <h5>Font Size</h5>
                    @foreach (var size in new[] { "Small", "Medium", "Large" })
                    {
                        <div class="form-check">
                            <input class="form-check-input" type="radio" name="fontSize"
                                   id="@($"fs-{size}")" value="@size"
                                   checked="@(_fontSize == size)"
                                   @onchange="() => _fontSize = size" />
                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                        </div>
                    }
                </div>

                <!-- Language -->
                <div class="mb-4">
                    <h5>Language</h5>
                    <select class="form-select" style="max-width:250px;" @bind="_language">
                        @foreach (var lang in _languages)
                        {
                            <option value="@lang">@lang</option>
                        }
                    </select>
                </div>

                <!-- Compact Mode -->
                <div class="mb-4">
                    <div class="form-check form-switch">
                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                        <label class="form-check-label" for="compactMode">Compact Mode</label>
                    </div>
                </div>

                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
                    @(_saving ? "Saving..." : "Save")
                </button>
            </div>

            <!-- Live Preview -->
            <div class="col-md-6">
                <h5>Preview</h5>
                <div class="appearance-preview @GetPreviewThemeClass()" style="@GetPreviewStyle()">
                    <div class="preview-header">
                        <strong>Sample Header</strong>
                    </div>
                    <div class="preview-body">
                        <p>This is how your content will look with the selected settings.</p>
                        <button class="btn btn-sm @GetPreviewButtonClass()">Sample Button</button>
                    </div>
                    @if (_compactMode)
                    {
                        <div class="preview-footer">
                            <small class="text-muted">Compact mode reduces spacing</small>
                        </div>
                    }
                    else
                    {
                        <div class="preview-footer mt-3">
                            <small class="text-muted">Standard spacing applied</small>
                        </div>
                    }
                </div>
            </div>
        </div>
    }
</div>

@code {
    private bool _loading = true;
    private bool _saving;
    private string? _message;

    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;

    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese" };

    protected override async Task OnInitializedAsync()
    {
        var settings = await SettingsService.GetAppearanceAsync();
        _theme = settings.Theme;
        _fontSize = settings.FontSize;
        _language = settings.Language;
        _compactMode = settings.CompactMode;
        _loading = false;
    }

    private async Task SaveAsync()
    {
        _saving = true;
        _message = null;
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        _message = "Appearance settings saved!";
        _saving = false;
    }

    private string GetPreviewThemeClass() => _theme switch
    {
        "Dark" => "preview-dark",
        _ => "preview-light"
    };

    private string GetPreviewStyle()
    {
        var size = _fontSize switch
        {
            "Small" => "0.85rem",
            "Large" => "1.15rem",
            _ => "1rem"
        };
        var padding = _compactMode ? "0.5rem" : "1rem";
        return $"font-size:{size}; padding:{padding};";
    }

    private string GetPreviewButtonClass() => _theme == "Dark" ? "btn-light" : "btn-primary";
}

