+                            <input class="form-check-input" type="radio" name="fontSize"
+                                   id="@($"fs-{size}")" value="@size"
+                                   checked="@(_fontSize == size)"
+                                   @onchange="() => _fontSize = size" />
+                            <label class="form-check-label" for="@($"fs-{size}")">@size</label>
+                        </div>
+                    }
+                </div>
+
+                <!-- Language -->
+                <div class="mb-4">
+                    <h5>Language</h5>
+                    <select class="form-select" style="max-width:250px;" @bind="_language">
+                        @foreach (var lang in _languages)
+                        {
+                            <option value="@lang">@lang</option>
+                        }
+                    </select>
+                </div>
+
+                <!-- Compact Mode -->
+                <div class="mb-4">
+                    <div class="form-check form-switch">
+                        <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
+                        <label class="form-check-label" for="compactMode">Compact Mode</label>
+                    </div>
+                </div>
+
+                <button class="btn btn-primary" @onclick="SaveAsync" disabled="@_saving">
+                    @(_saving ? "Saving..." : "Save")
+                </button>
+            </div>
+
+            <!-- Live Preview -->
+            <div class="col-md-6">
+                <h5>Preview</h5>
+                <div class="appearance-preview @GetPreviewThemeClass()" style="@GetPreviewStyle()">
+                    <div class="preview-header">
+                        <strong>Sample Header</strong>
+                    </div>
+                    <div class="preview-body">
+                        <p>This is how your content will look with the selected settings.</p>
+                        <button class="btn btn-sm @GetPreviewButtonClass()">Sample Button</button>
+                    </div>
+                    @if (_compactMode)
+                    {
+                        <div class="preview-footer">
+                            <small class="text-muted">Compact mode reduces spacing</small>
+                        </div>
+                    }
+                    else
+                    {
+                        <div class="preview-footer mt-3">
+                            <small class="text-muted">Standard spacing applied</small>
+                        </div>
+                    }
+                </div>
+            </div>
+        </div>
+    }
+</div>
+
+@code {
+    private bool _loading = true;
+    private bool _saving;
+    private string? _message;
+
+    private string _theme = "Light";
+    private string _fontSize = "Medium";
+    private string _language = "English";
+    private bool _compactMode;
+
+    private static readonly string[] _languages = { "English", "Spanish", "French", "German", "Japanese", "Chinese", "Portuguese" };
+
+    protected override async Task OnInitializedAsync()
+    {
+        var settings = await SettingsService.GetAppearanceAsync();
+        _theme = settings.Theme;
+        _fontSize = settings.FontSize;
+        _language = settings.Language;
+        _compactMode = settings.CompactMode;
+        _loading = false;
+    }
+
+    private async Task SaveAsync()
+    {
+        _saving = true;
+        _message = null;
+        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
+        await SettingsService.SaveAppearanceAsync(settings);
+        _message = "Appearance settings saved!";
+        _saving = false;
+    }
+
+    private string GetPreviewThemeClass() => _theme switch
+    {
+        "Dark" => "preview-dark",
+        _ => "preview-light"
+    };
+
+    private string GetPreviewStyle()
+    {
+        var size = _fontSize switch
+        {
+            "Small" => "0.85rem",
+            "Large" => "1.15rem",
+            _ => "1rem"
+        };
+        var padding = _compactMode ? "0.5rem" : "1rem";
+        return $"font-size:{size}; padding:{padding};";
+    }
+
+    private string GetPreviewButtonClass() => _theme == "Dark" ? "btn-light" : "btn-primary";
+}
+

toolArgs.file_text:
@page "/settings"
@namespace sv_eaddef93421840ad96f12f92eec1e88d.Components.Pages.Settings
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<div class="settings-layout">
    <SettingsSidebar ActiveSection="@_activeSection" OnSectionChanged="section => _activeSection = section" />

    <div class="settings-content">
        @switch (_activeSection)
        {
            case "Profile":
                <ProfileSection />
                break;
            case "Notifications":
                <NotificationsSection />
                break;
            case "Security":
                <SecuritySection />
                break;
            case "Appearance":
                <AppearanceSection />
                break;
        }
    </div>
</div>

@code {
    private string _activeSection = "Profile";
}

/* Settings page layout */
.settings-layout {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
}

/* Sidebar */
.settings-sidebar {
    width: 220px;
    flex-shrink: 0;
    background: #f8f9fa;
    border-right: 1px solid #dee2e6;
    padding-top: 1rem;
}

.settings-sidebar .nav-link {
    color: #495057;
    border-radius: 0;
    padding: 0.6rem 1rem;
    text-align: left;
    width: 100%;
    border: none;
    background: none;
    font-size: 0.95rem;
    transition: background-color 0.15s;
}

.settings-sidebar .nav-link:hover {
    background-color: #e9ecef;
}

.settings-sidebar .nav-link.active {
    background-color: #0d6efd;
    color: #fff;
    font-weight: 500;
}

/* Content area */
.settings-content {
    flex: 1;
    padding: 1.5rem 2rem;
    max-width: 900px;
}

.settings-section h3 {
    margin-bottom: 0.25rem;
}

/* Appearance preview */
.appearance-preview {
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    overflow: hidden;
    transition: all 0.2s ease;
}

.appearance-preview .preview-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #dee2e6;
}

.appearance-preview .preview-body {
    padding: 1rem;
}

.appearance-preview .preview-footer {
    padding: 0.5rem 1rem;
    border-top: 1px solid #dee2e6;
}

.preview-light {
    background-color: #ffffff;
    color: #212529;
}

.preview-light .preview-header {
    background-color: #f8f9fa;
}

.preview-dark {
    background-color: #212529;
    color: #f8f9fa;
    border-color: #495057;
}

.preview-dark .preview-header {
    background-color: #2c3034;
    border-color: #495057;
}

.preview-dark .preview-body {
    color: #dee2e6;
}

.preview-dark .preview-footer {
    border-color: #495057;
}

